// Safe HTTP probe tool for AI Agent.
// Always returns a structured result — never throws.
// Distinguishes network errors (unreachable, timeout, DNS) from HTTP errors (4xx/5xx).

const input = $input.first().json;
const url = input.url;
const method = (input.method || 'GET').toUpperCase();
// Hard cap timeout at 15s so the agent never waits longer
const timeoutMs = Math.min(Number(input.timeout_ms) || 10000, 15000);

if (!url || typeof url !== 'string') {
  return [{ json: {
    ok: false,
    error_type: 'invalid_input',
    message: 'url parameter is required and must be a string',
    url: null
  }}];
}

// Basic URL validation — reject non-http(s) schemes early
if (!/^https?:\/\//i.test(url)) {
  return [{ json: {
    ok: false,
    error_type: 'invalid_input',
    message: 'url must start with http:// or https://',
    url
  }}];
}

const controller = new AbortController();
const timer = setTimeout(() => controller.abort(), timeoutMs);
const started = Date.now();

try {
  const response = await fetch(url, {
    method,
    signal: controller.signal,
    redirect: 'follow',
    headers: { 'User-Agent': 'n8n-devops-assistant/1.0' }
  });
  clearTimeout(timer);

  const elapsed = Date.now() - started;

  // Limit body size to avoid flooding the agent context window
  let body = '';
  try {
    const rawBody = await response.text();
    body = rawBody.length > 2000
      ? rawBody.slice(0, 2000) + `\n... [truncated, total ${rawBody.length} bytes]`
      : rawBody;
  } catch (bodyErr) {
    body = `[could not read body: ${bodyErr.message}]`;
  }

  return [{ json: {
    ok: response.ok,
    error_type: null,
    status: response.status,
    status_text: response.statusText,
    url: response.url,
    final_url: response.url !== url ? response.url : undefined,
    elapsed_ms: elapsed,
    body,
    note: response.ok
      ? 'Host reachable and responded successfully.'
      : `Host reachable but returned HTTP ${response.status}. This may be the root cause of the CI failure.`
  }}];
} catch (err) {
  clearTimeout(timer);
  const elapsed = Date.now() - started;

  // Classify the failure so the agent can reason about it
  let errorType = 'unknown';
  let humanMessage = err.message;

  if (err.name === 'AbortError') {
    errorType = 'timeout';
    humanMessage = `Request timed out after ${timeoutMs}ms. Host is unreachable or extremely slow.`;
  } else if (/ENOTFOUND|EAI_AGAIN|getaddrinfo/i.test(err.message)) {
    errorType = 'dns_failure';
    humanMessage = 'DNS resolution failed. The hostname does not exist or is not resolvable.';
  } else if (/ECONNREFUSED/i.test(err.message)) {
    errorType = 'connection_refused';
    humanMessage = 'Connection refused. The host is up but nothing is listening on this port.';
  } else if (/ECONNRESET|EPIPE/i.test(err.message)) {
    errorType = 'connection_reset';
    humanMessage = 'Connection reset by peer.';
  } else if (/certificate|SSL|TLS|self-signed|unable to verify/i.test(err.message)) {
    errorType = 'tls_error';
    humanMessage = `TLS/SSL error: ${err.message}`;
  } else if (/ETIMEDOUT/i.test(err.message)) {
    errorType = 'timeout';
    humanMessage = 'Socket timeout — host did not respond in time.';
  }

  return [{ json: {
    ok: false,
    error_type: errorType,
    status: null,
    url,
    elapsed_ms: elapsed,
    message: humanMessage,
    note: 'This is likely the root cause of the CI failure — the dependency is not fetchable from the runner network.'
  }}];
}
